// ─── Extract core fields from the incoming webhook payload ───
const payload  = $json.body || {};
const data     = payload.data || {};

const sessionId   = payload.sessionId || '';
const msgType     = data.type || 'chat';          // chat | image | video | audio | ptt | document
const from        = data.from || '';
const phoneNumber = from.replace('@c.us', '');
const body        = data.body || '';
const mediaUrl    = data.mediaUrl || null;
const fileName    = data.fileName || null;
const caption     = data.caption || '';
const mimeType    = data.mimetype || '';

// Map wppconnect type to a cleaner category
let category = 'text';
if (msgType === 'image')                       category = 'image';
else if (msgType === 'video')                  category = 'video';
else if (msgType === 'audio' || msgType === 'ptt') category = 'audio';
else if (msgType === 'document')               category = 'document';
else if (msgType === 'sticker')                category = 'sticker';
else if (msgType === 'location')               category = 'location';

return {
  sessionId,
  phoneNumber,
  category,
  rawType: msgType,
  body,
  mediaUrl,
  fileName,
  caption,
  mimeType
};

// ─── Handle TEXT messages ───
const text       = ($json.body || '').toLowerCase();
const phone      = $json.phoneNumber;
const sessionId  = $json.sessionId;

let reply = 'شكراً لتواصلك! سنرد عليك قريباً.\nThank you! We will reply soon.';

if (text.includes('مرحبا') || text.includes('هلا') || text.includes('hello') || text.includes('hi')) {
  reply = 'أهلاً وسهلاً! 👋 كيف يمكنني مساعدتك؟\nHello! 👋 How can I help you?';
} else if (text.includes('سعر') || text.includes('price') || text.includes('كم')) {
  reply = 'يرجى التواصل مع فريق المبيعات للاستفسار عن الأسعار 📋\nPlease contact our sales team for pricing info.';
} else if (text.includes('وقت') || text.includes('دوام') || text.includes('hours') || text.includes('time')) {
  reply = 'أوقات العمل: الأحد – الخميس 9 صباحاً – 6 مساءً 🕘\nWorking hours: Sun–Thu 9 AM – 6 PM';
}

return { sessionId, phoneNumber: phone, replyText: reply, replyType: 'text' };

// ─── Handle IMAGE messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const caption   = $json.caption || '';
const mediaUrl  = $json.mediaUrl || '';

// Example: acknowledge the image
const reply = `تم استلام صورتك 📷${caption ? ' — ' + caption : ''}\nImage received 📷${caption ? ' — ' + caption : ''}`;

return { sessionId, phoneNumber: phone, replyText: reply, replyType: 'text', receivedMediaUrl: mediaUrl };

// ─── Handle VIDEO messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const caption   = $json.caption || '';
const mediaUrl  = $json.mediaUrl || '';

const reply = `تم استلام الفيديو 🎬${caption ? ' — ' + caption : ''}\nVideo received 🎬${caption ? ' — ' + caption : ''}`;

return { sessionId, phoneNumber: phone, replyText: reply, replyType: 'text', receivedMediaUrl: mediaUrl };

// ─── Handle AUDIO / Voice Note messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const mediaUrl  = $json.mediaUrl || '';
const isVoice   = $json.rawType === 'ptt';  // ptt = push-to-talk (voice note)

const reply = isVoice
  ? 'تم استلام رسالتك الصوتية 🎙️\nVoice note received 🎙️'
  : 'تم استلام الملف الصوتي 🎵\nAudio file received 🎵';

return { sessionId, phoneNumber: phone, replyText: reply, replyType: 'text', receivedMediaUrl: mediaUrl };

// ─── Handle DOCUMENT messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const fileName  = $json.fileName || 'document';
const mediaUrl  = $json.mediaUrl || '';
const mimeType  = $json.mimeType || '';

const reply = `تم استلام الملف 📄: ${fileName}\nDocument received 📄: ${fileName}`;

return { sessionId, phoneNumber: phone, replyText: reply, replyType: 'text', receivedMediaUrl: mediaUrl, fileName, mimeType };

// ─── Merge all handler outputs into one stream ───
// This node receives data from all 5 handlers above.
// Pass everything through unchanged.
return $json;
